import "core-js/modules/es.array.push.js";
import "core-js/modules/es.iterator.constructor.js";
import "core-js/modules/es.iterator.find.js";
import "core-js/modules/es.iterator.map.js";
import { Chart, registerables } from 'chart.js';
import { getStatsByFarm, getDetectionStats, getDetectionRecordsWithImages, getTimeSeriesStats } from '@/api/statsApi';

// 注册 Chart.js 组件
Chart.register(...registerables);
export default {
  name: 'StatsPage',
  data() {
    return {
      loading: false,
      lastUpdateTime: null,
      // 全局汇总
      globalStats: {
        total_images: 0,
        total_pigs: 0,
        today_images: 0,
        today_pigs: 0
      },
      // 猪场统计
      farmStats: [],
      farmStatsLoading: false,
      // 时间序列数据
      timeSeriesData: [],
      timeSeriesLoading: false,
      timeSeriesGranularity: 'day',
      // day 或 month
      timeSeriesChart: null,
      // 图片回看
      selectedFarmId: null,
      gallery: [],
      galleryTotal: 0,
      galleryPage: 1,
      galleryPageSize: 12,
      galleryLoading: false,
      // 预览弹窗
      previewRecord: null
    };
  },
  computed: {
    year() {
      return new Date().getFullYear();
    },
    globalSummaryCards() {
      return [{
        icon: '🖼️',
        label: '识别图片总数',
        value: this.globalStats.total_images.toLocaleString()
      }, {
        icon: '🐷',
        label: '识别猪只总数',
        value: this.globalStats.total_pigs.toLocaleString()
      }, {
        icon: '📅',
        label: '今日识别图片',
        value: this.globalStats.today_images.toLocaleString()
      }, {
        icon: '🐖',
        label: '今日识别猪只',
        value: this.globalStats.today_pigs.toLocaleString()
      }];
    },
    selectedFarmName() {
      if (this.selectedFarmId === null) return null;
      const farm = this.farmStats.find(f => f.farm_id === this.selectedFarmId);
      return farm ? farm.farm_name || '未分配猪场' : null;
    },
    galleryTotalPages() {
      return Math.ceil(this.galleryTotal / this.galleryPageSize) || 1;
    },
    visiblePages() {
      const cur = this.galleryPage;
      const total = this.galleryTotalPages;
      const pages = [];
      for (let p = Math.max(1, cur - 2); p <= Math.min(total, cur + 2); p++) {
        pages.push(p);
      }
      return pages;
    }
  },
  created() {
    this.loadAll();
  },
  mounted() {
    // 组件挂载后初始化图表
    this.$nextTick(() => {
      if (this.timeSeriesData.length > 0) {
        this.updateTimeSeriesChart();
      }
    });
  },
  watch: {
    // 监听时间序列数据变化，自动更新图表
    timeSeriesData: {
      handler() {
        this.$nextTick(() => {
          this.updateTimeSeriesChart();
        });
      },
      deep: true
    }
  },
  methods: {
    async loadAll() {
      this.loading = true;
      await Promise.all([this.loadGlobalStats(), this.loadFarmStats(), this.loadGallery(), this.loadTimeSeriesData()]);
      this.lastUpdateTime = new Date().toLocaleTimeString('zh-CN', {
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit'
      });
      this.loading = false;
    },
    async loadTimeSeriesData() {
      this.timeSeriesLoading = true;
      try {
        const res = await getTimeSeriesStats({
          granularity: this.timeSeriesGranularity,
          farmId: this.selectedFarmId
        });
        console.log('Time series data response:', res);
        if (res && res.success) {
          this.timeSeriesData = res.data;
          console.log('Updated timeSeriesData:', this.timeSeriesData);
          this.$nextTick(() => {
            this.updateTimeSeriesChart();
          });
        } else {
          console.error('Invalid response format:', res);
          this.timeSeriesData = [];
        }
      } catch (e) {
        console.error(e);
      } finally {
        this.timeSeriesLoading = false;
      }
    },
    updateTimeSeriesChart() {
      console.log('Updating time series chart...');
      console.log('Data:', this.timeSeriesData);

      // 使用ref获取canvas元素
      const canvasElement = this.$refs.timeSeriesChartRef;
      console.log('Canvas element:', canvasElement);
      if (!canvasElement) {
        console.error('Chart canvas element not found');
        return;
      }
      const ctx = canvasElement.getContext('2d');
      console.log('Chart context:', ctx);
      if (!ctx) {
        console.error('Failed to get canvas context');
        return;
      }

      // 销毁旧图表
      if (this.timeSeriesChart) {
        console.log('Destroying old chart');
        this.timeSeriesChart.destroy();
      }

      // 准备数据
      const labels = this.timeSeriesData.map(item => item.date);
      const imageData = this.timeSeriesData.map(item => item.images);
      const pigData = this.timeSeriesData.map(item => item.pigs);
      console.log('Labels:', labels);
      console.log('Image data:', imageData);
      console.log('Pig data:', pigData);
      try {
        // 创建新图表
        this.timeSeriesChart = new Chart(ctx, {
          type: 'line',
          data: {
            labels: labels,
            datasets: [{
              label: '上传图片数',
              data: imageData,
              borderColor: '#007aff',
              backgroundColor: 'rgba(0, 122, 255, 0.1)',
              tension: 0.4,
              fill: true
            }, {
              label: '识别猪只数',
              data: pigData,
              borderColor: '#34c759',
              backgroundColor: 'rgba(52, 199, 89, 0.1)',
              tension: 0.4,
              fill: true
            }]
          },
          options: {
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
              title: {
                display: true,
                text: this.timeSeriesGranularity === 'day' ? '每日数据统计' : '每月数据统计',
                font: {
                  size: 14,
                  weight: '600'
                }
              },
              legend: {
                position: 'top'
              }
            },
            scales: {
              y: {
                beginAtZero: true,
                ticks: {
                  precision: 0
                }
              }
            }
          }
        });
        console.log('Chart created successfully');
      } catch (error) {
        console.error('Error creating chart:', error);
      }
    },
    changeTimeSeriesGranularity(granularity) {
      this.timeSeriesGranularity = granularity;
      this.loadTimeSeriesData();
    },
    async loadGlobalStats() {
      try {
        const res = await getDetectionStats(null);
        if (res.success) this.globalStats = res.data;
      } catch (e) {
        console.error(e);
      }
    },
    async loadFarmStats() {
      this.farmStatsLoading = true;
      try {
        const res = await getStatsByFarm();
        if (res.success) this.farmStats = res.data;
      } catch (e) {
        console.error(e);
      } finally {
        this.farmStatsLoading = false;
      }
    },
    async loadGallery() {
      this.galleryLoading = true;
      try {
        const res = await getDetectionRecordsWithImages({
          farmId: this.selectedFarmId,
          page: this.galleryPage,
          pageSize: this.galleryPageSize
        });
        if (res.success) {
          this.gallery = res.data;
          this.galleryTotal = res.total;
        }
      } catch (e) {
        console.error(e);
      } finally {
        this.galleryLoading = false;
      }
    },
    selectFarmForGallery(farmId) {
      if (this.selectedFarmId === farmId) {
        this.clearFarmFilter();
        return;
      }
      this.selectedFarmId = farmId;
      this.galleryPage = 1;
      this.loadGallery();
      this.loadTimeSeriesData();
    },
    clearFarmFilter() {
      this.selectedFarmId = null;
      this.galleryPage = 1;
      this.loadGallery();
      this.loadTimeSeriesData();
    },
    goToPage(page) {
      this.galleryPage = page;
      this.loadGallery();
      this.$nextTick(() => {
        const el = document.querySelector('.gallery-section');
        if (el) el.scrollIntoView({
          behavior: 'smooth',
          block: 'start'
        });
      });
    },
    openRecord(record) {
      this.previewRecord = record;
      document.body.style.overflow = 'hidden';
    },
    closePreview() {
      this.previewRecord = null;
      document.body.style.overflow = '';
    },
    formatDate(dateStr) {
      if (!dateStr) return '—';
      return new Date(dateStr).toLocaleString('zh-CN', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      });
    },
    formatDateShort(dateStr) {
      if (!dateStr) return '—';
      return new Date(dateStr).toLocaleString('zh-CN', {
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit'
      });
    }
  }
};
